sql:
SELECT MAX(concentration_ng_per_g)
FROM concentration_data
WHERE element = '238U';

SELECT AVG(age_uncorrected_yr_BP) AS average_uncorrected_age
FROM samples
WHERE collector_id = (SELECT user_id FROM users WHERE user_name = 'Alice Johnson');

SELECT ratio_name
FROM isotopic_ratios
WHERE sample_id = 1;

SELECT DISTINCT sample_id
FROM reporting
WHERE report_date = (
  SELECT MAX(report_date)
  FROM reporting
);

external_knowledge:
; Age correction refers to a process of adjusting the age of a sample to account for various factors that may affect its actual age, such as contamination or equipment calibration; 
; 232Th is a radioactive isotope of thorium often used in scientific research, particularly in geochronology and environmental science; 
; Distance from the base refers to the depth or position of a sample relative to a fixed point, often used in sediment core or geological samples.

sql:
SELECT COUNT(ratio_id) as total_isotopic_ratios, sample_id
FROM isotopic_ratios
GROUP BY sample_id;
